import{bV as e,aL as l,u as i,G as t}from"./chunks/framework.BfzMay2U.js";const h=JSON.parse('{"title":"claude使用注意","description":"","frontmatter":{"title":"claude使用注意","date":"2026-07-12T15:42:11.000Z"},"headers":[],"relativePath":"ai/tools/claude-limit.md","filePath":"ai/tools/claude-limit.md"}'),p={name:"ai/tools/claude-limit.md"};function o(r,a,s,c,d,n){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="claude-使用注意" tabindex="-1">Claude 使用注意 <a class="header-anchor" href="#claude-使用注意" aria-label="Permalink to &quot;Claude 使用注意&quot;">​</a></h1><h2 id="怎么尽可能避免被封" tabindex="-1">怎么尽可能避免被封 <a class="header-anchor" href="#怎么尽可能避免被封" aria-label="Permalink to &quot;怎么尽可能避免被封&quot;">​</a></h2><p>尽量固定IP，可以长期稳定使用</p><ol><li><p>新账号前两周，只用 Claude Desktop里的Claude Code，不碰 CLI</p></li><li><p>新账号阶段，不使用 OpenCode/OpenClaw/CraftAgent等第三方客户端</p></li><li><p>通过App Store或Google Play 订阅，不在官网直接刷卡</p></li><li><p>从$20 Pro Plan起步，多次触碰限额后再自然升级</p></li><li><p>升级Max Plan后前两周，触发用量上限不超过3次</p></li><li><p>账号要有作息一一不要24小时持续高负载</p></li><li><p>IP类型无所谓，但别用万人骑的公共代理，且早期不要频繁切换IP</p></li><li><p>被封过号的，换账号前彻底清除电脑上一切Claude相关文件(指纹重置)</p></li><li><p>不要共享账号给任何人</p></li><li><p>养号期约一个月(首次续费后)，之后上述限制可以有序放松</p></li></ol><h2 id="ip-一致性" tabindex="-1">ip 一致性 <a class="header-anchor" href="#ip-一致性" aria-label="Permalink to &quot;ip 一致性&quot;">​</a></h2><p>建议参照的<code>ip</code>标准：打开：<a href="https://ip.net.coffee/claude/" target="_blank" rel="noreferrer">https://ip.net.coffee/claude/</a></p><p>保持 3 个 <code>ip</code>地址一致</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260712154531971.png" alt="image-20260712154531971" loading="lazy"></p><blockquote><p>我这里只是提供截图案例，不一定一致</p></blockquote><hr><p>AI 信任评分越高越好</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260712154700190.png" alt="image-20260712154700190" loading="lazy"></p><hr><p>DNS 泄露检测，不能有中国。</p><hr><p>你的🪜设置，不要有<code>ipv6</code>，不断切换网络环境，直到符合上面标准。</p>',16)])])}const m=e(p,[["render",o]]);export{h as __pageData,m as default};
